import{_ as r,E as s,c as i,J as l,w as o,V as e,o as n,m as a}from"./chunks/framework.vTT8XiEL.js";const T=JSON.parse('{"title":"视野修炼第60期","description":"① 通义灵码 ② System Design 101 -  ③ ofajs - 不需要打包的MVVM框架 ④ tailspin - 实时高亮展示日志 ⑤ Olive - 开源的跨平台的视频编辑器 ⑥ 深入架构原理与实践 ⑦ Clash 相关资讯","frontmatter":{"description":"① 通义灵码 ② System Design 101 -  ③ ofajs - 不需要打包的MVVM框架 ④ tailspin - 实时高亮展示日志 ⑤ Olive - 开源的跨平台的视频编辑器 ⑥ 深入架构原理与实践 ⑦ Clash 相关资讯","hidden":true,"cover":null,"outline":[2,3],"recommend":-60},"headers":[],"relativePath":"weekly/2023-11-05.md","filePath":"weekly/2023-11-05.md","lastUpdated":1699796197000}'),h={name:"weekly/2023-11-05.md"},p=e('<h1 id="视野修炼第60期" tabindex="-1">视野修炼第60期 <a class="header-anchor" href="#视野修炼第60期" aria-label="Permalink to &quot;视野修炼第60期&quot;">​</a></h1><p><em>笔者在GitHub开了个 discussion <a href="https://github.com/ATQQ/sugar-blog/discussions/123" target="_blank" rel="noreferrer">🔥 技术&amp;开源&amp;文章推荐</a>，欢迎读者推荐贡献内容或者知识渠道</em></p><p>欢迎来到第 60 期的【视野修炼 - 技术周刊】，下面是本期的精选内容简介</p><nav class="table-of-contents"><ul><li><a href="#🔥强烈推荐">🔥强烈推荐</a><ul><li><a href="#_1-通义灵码">1. 通义灵码</a></li><li><a href="#_2-system-design-101">2. System Design 101 -</a></li></ul></li><li><a href="#🔧开源工具-技术资讯">🔧开源工具&amp;技术资讯</a><ul><li><a href="#_3-ofajs-不需要打包的mvvm框架">3. ofajs - 不需要打包的MVVM框架</a></li><li><a href="#_4-tailspin-实时高亮展示日志">4. tailspin - 实时高亮展示日志</a></li><li><a href="#_5-olive-开源的跨平台的视频编辑器">5. Olive - 开源的跨平台的视频编辑器</a></li><li><a href="#_6-深入架构原理与实践">6. 深入架构原理与实践</a></li><li><a href="#_7-clash-相关资讯">7. Clash 相关资讯</a></li></ul></li><li><a href="#😛趣图">😛趣图</a></li><li><a href="#⭐️强力推荐关注">⭐️强力推荐关注</a></li></ul></nav>',4),c=a("p",null,[a("strong",null,"​也推荐大家关注一下最后的推荐内容（周刊的主要内容来源渠道）")],-1),m=e('<p>下面开始本期内容的介绍<strong>ღ( ´･ᴗ･` )比心</strong>。</p><h2 id="🔥强烈推荐" tabindex="-1">🔥强烈推荐 <a class="header-anchor" href="#🔥强烈推荐" aria-label="Permalink to &quot;🔥强烈推荐&quot;">​</a></h2><h3 id="_1-通义灵码" tabindex="-1"><a href="https://tongyi.aliyun.com/lingma" target="_blank" rel="noreferrer">1. 通义灵码</a> <a class="header-anchor" href="#_1-通义灵码" aria-label="Permalink to &quot;[1. 通义灵码](https://tongyi.aliyun.com/lingma)&quot;">​</a></h3><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3MzA3NjczMA==699173076730" alt=""></p><p>无法使用 Copilot 的朋友可以试试，使用体验差不多，提示速度更快，目前免费试用</p><p><em>笔者体验了一下，效果还是很不错，又能把 Copilot(10$/月) 的钱省下来了</em></p><h3 id="_2-system-design-101" tabindex="-1"><a href="https://github.com/ByteByteGoHq/system-design-101#rest-api-vs-graphql" target="_blank" rel="noreferrer">2. System Design 101</a> - <a class="header-anchor" href="#_2-system-design-101" aria-label="Permalink to &quot;[2. System Design 101](https://github.com/ByteByteGoHq/system-design-101#rest-api-vs-graphql) -&quot;">​</a></h3><p>这个开源项目使用可视化的图表介绍复杂系统</p><p>例如：<strong>REST API vs. GraphQL</strong></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3OTQwNjU2NA==699179406564" alt=""></p><p><strong>DevOps vs. SRE vs. Platform Engineering</strong></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3OTcyMjY5MQ==699179722691" alt=""></p><blockquote><p>可以帮你学习如何绘制架构图</p></blockquote><h2 id="🔧开源工具-技术资讯" tabindex="-1">🔧开源工具&amp;技术资讯 <a class="header-anchor" href="#🔧开源工具-技术资讯" aria-label="Permalink to &quot;🔧开源工具&amp;技术资讯&quot;">​</a></h2><h3 id="_3-ofajs-不需要打包的mvvm框架" tabindex="-1"><a href="https://ofajs.com/cn/index.html" target="_blank" rel="noreferrer">3. ofajs - 不需要打包的MVVM框架</a> <a class="header-anchor" href="#_3-ofajs-不需要打包的mvvm框架" aria-label="Permalink to &quot;[3. ofajs - 不需要打包的MVVM框架](https://ofajs.com/cn/index.html)&quot;">​</a></h3><p>一个新的玩具，基于 Web Components 开发</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3MjY0NDE1NA==699172644154" alt=""></p><p>目前没看见 benchmark 数据，不知道性能如何</p><p>有一套简洁的模板语法，有点类似 Vue</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3Mjg0NDE3NQ==699172844175" alt=""></p><p>喜欢尝鲜的朋友可以试试</p><h3 id="_4-tailspin-实时高亮展示日志" tabindex="-1"><a href="https://github.com/bensadeh/tailspin" target="_blank" rel="noreferrer">4. tailspin</a> - 实时高亮展示日志 <a class="header-anchor" href="#_4-tailspin-实时高亮展示日志" aria-label="Permalink to &quot;[4. tailspin](https://github.com/bensadeh/tailspin) - 实时高亮展示日志&quot;">​</a></h3><p>一个命令行工具，实时高亮显示日志文件。</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3NTcxNzUzNQ==699175717535" alt=""></p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3NDIyODgyNQ==699174228825" alt=""></p><p><em>通常linux 机器上实时查看日志都是用 tail</em></p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 实时显示最后8行</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file.log</span></span></code></pre></div><h3 id="_5-olive-开源的跨平台的视频编辑器" tabindex="-1"><a href="https://github.com/olive-editor/olive" target="_blank" rel="noreferrer">5. Olive - 开源的跨平台的视频编辑器</a> <a class="header-anchor" href="#_5-olive-开源的跨平台的视频编辑器" aria-label="Permalink to &quot;[5. Olive - 开源的跨平台的视频编辑器](https://github.com/olive-editor/olive)&quot;">​</a></h3><p>适合快速编辑生成短视频，安装包非常的小。</p><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3NTMxMTM1OQ==699175311359" alt=""></p><h3 id="_6-深入架构原理与实践" tabindex="-1"><a href="https://www.thebyte.com.cn/" target="_blank" rel="noreferrer">6. 深入架构原理与实践</a> <a class="header-anchor" href="#_6-深入架构原理与实践" aria-label="Permalink to &quot;[6. 深入架构原理与实践](https://www.thebyte.com.cn/)&quot;">​</a></h3><blockquote><p>这是一本关于架构设计的开源书籍</p></blockquote><blockquote><p>整个系列的内容主要集中在 网络、集群以及服务治理、FinOps 这三个主题，这也代表着基础架构的几个核心：稳定、效率、成本。</p></blockquote><h3 id="_7-clash-相关资讯" tabindex="-1">7. Clash 相关资讯 <a class="header-anchor" href="#_7-clash-相关资讯" aria-label="Permalink to &quot;7. Clash 相关资讯&quot;">​</a></h3><p>本周技术圈的一个大新闻，事发起源于 clash for windows 作者删库（Twitter上泄露了个人隐私信息）</p><p>然后 clash 生态相关的许多开源仓库和站点都进行 归档/删库/网站404 等操作</p><p><strong>DDDD</strong>，<em>设备上还装有相关软件的建议不要更新/卸载</em></p><h2 id="😛趣图" tabindex="-1">😛趣图 <a class="header-anchor" href="#😛趣图" aria-label="Permalink to &quot;😛趣图&quot;">​</a></h2><p><img src="https://img.cdn.sugarat.top/mdImg/MTY5OTE3Mjk1OTM3Mg==699172959372" alt=""></p><hr><p>篇幅有限，如果你还没看够，可移步后面的推荐渠道，继续游览，历史周刊（&lt;20）<a href="https://sugarat.top/weekly/index.html" target="_blank" rel="noreferrer">移步博客</a></p><h2 id="⭐️强力推荐关注" tabindex="-1">⭐️强力推荐关注 <a class="header-anchor" href="#⭐️强力推荐关注" aria-label="Permalink to &quot;⭐️强力推荐关注&quot;">​</a></h2><ul><li><a href="https://www.ruanyifeng.com/blog/archives.html" target="_blank" rel="noreferrer">阮一峰: 科技爱好者周刊</a> - 记录每周值得分享的科技内容，周五发布</li><li><a href="https://mdhweekly.com/" target="_blank" rel="noreferrer">云谦：MDH 前端周刊</a> - 前端资讯和分享</li><li><a href="https://github.com/Geekhyt/weekly" target="_blank" rel="noreferrer">童欧巴：前端食堂</a> - 你的前端食堂，吃好每一顿饭</li><li><a href="https://fed.chanceyu.com/" target="_blank" rel="noreferrer">前端RSS</a> - 根据 RSS 订阅源抓取最新前端技术文章</li><li><a href="https://daily-blog.chlinlearn.top/" target="_blank" rel="noreferrer">值得一读技术博客</a> - 每天进步一点点，每天分享有料的技术文章！</li></ul>',43);function d(g,u,_,f,b,k){const t=s("center");return n(),i("div",null,[p,l(t,null,{default:o(()=>[c]),_:1}),m])}const v=r(h,[["render",d]]);export{T as __pageData,v as default};
